    async def export_experiment_spans(
        self,
        experiment_id: str,
        *,
        export: str,
        page: int,
        page_size: int,
        sort_by: str,
        start_time: str,
        end_time: str,
        authorization: str,
        request_options: typing.Optional[RequestOptions] = None,
    ) -> AsyncPager[typing.Dict[str, typing.Any], ExportExperimentSpansResponse]:
        """
        Export all experiment spans. Supports pagination and sorting.

        Parameters
        ----------
        experiment_id : str
            The ID of the experiment to export spans from.

        export : str
            Set to 1 or true to trigger export.

        page : int
            Page number (default: 1).

        page_size : int
            Number of results per page (default: 100).

        sort_by : str
            Sort field (e.g., "-cost", "-start_time", "name").

        start_time : str
            Filter start time (ISO format).

        end_time : str
            Filter end time (ISO format).

        authorization : str
            Bearer token. Use `Bearer YOUR_API_KEY`.

        request_options : typing.Optional[RequestOptions]
            Request-specific configuration.

        Returns
        -------
        AsyncPager[typing.Dict[str, typing.Any], ExportExperimentSpansResponse]
            Successful response for Export experiment spans
        """
        page = page if page is not None else 1

        _response = await self._client_wrapper.httpx_client.request(
            f"api/v2/experiments/{jsonable_encoder(experiment_id)}/logs/",
            method="GET",
            params={
                "export": export,
                "page": page,
                "page_size": page_size,
                "sort_by": sort_by,
                "start_time": start_time,
                "end_time": end_time,
            },
            headers={
                "Authorization": str(authorization) if authorization is not None else None,
            },
            request_options=request_options,
        )
        try:
            if 200 <= _response.status_code < 300:
                _parsed_response = typing.cast(
                    ExportExperimentSpansResponse,
                    parse_obj_as(
                        type_=ExportExperimentSpansResponse,  # type: ignore
                        object_=_response.json(),
                    ),
                )
                _items = _parsed_response.results
                _has_next = True

                async def _get_next():
                    return await self.export_experiment_spans(
                        experiment_id,
                        export=export,
                        page=page + 1,
                        page_size=page_size,
                        sort_by=sort_by,
                        start_time=start_time,
                        end_time=end_time,
                        authorization=authorization,
                        request_options=request_options,
                    )

                return AsyncPager(has_next=_has_next, items=_items, get_next=_get_next, response=_parsed_response)
            if _response.status_code == 401:
                raise UnauthorizedError(
                    headers=dict(_response.headers),
                    body=typing.cast(
                        typing.Any,
                        parse_obj_as(
                            type_=typing.Any,  # type: ignore
                            object_=_response.json(),
                        ),
                    ),
                )
            _response_json = _response.json()
        except JSONDecodeError:
            raise ApiError(status_code=_response.status_code, headers=dict(_response.headers), body=_response.text)
        raise ApiError(status_code=_response.status_code, headers=dict(_response.headers), body=_response_json)
